// --- pulse-meta parser (inline) ---
const decodeEntities = (s) => s.replace(/&quot;/g, '"').replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&#39;/g, "'");
const extractMeta = (html) => {
  if (!html) return null;
  // Pattern 1: raw markdown ```pulse-meta\n{...}\n```
  let m = html.match(/```pulse-meta\n([\s\S]*?)\n```/);
  if (m) try { return JSON.parse(m[1].trim()); } catch(e) { /* fall through */ }
  // Pattern 2: HTML with class="language-pulse-meta"
  m = html.match(/<pre><code\s+class="language-pulse-meta">([\s\S]*?)<\/code><\/pre>/);
  if (m) try { return JSON.parse(decodeEntities(m[1].trim())); } catch(e) { return null; }
  // Pattern 3: HTML with any class (e.g. language-json)
  m = html.match(/<pre><code\s[^>]*>([\s\S]*?)<\/code><\/pre>/);
  if (m) { const c = decodeEntities(m[1].trim()); if (c.includes('"schema_version"')) try { return JSON.parse(c); } catch(e) {} }
  // Pattern 4: HTML no class
  m = html.match(/<pre><code>([\s\S]*?)<\/code><\/pre>/);
  if (m) { const c = decodeEntities(m[1].trim()); if (c.includes('"schema_version"')) try { return JSON.parse(c); } catch(e) {} }
  // Pattern: inline <code> (Plane editor format, <br> line breaks)
  m = html.match(/<code[^>]*>([\s\S]*?)<\/code>/);
  if (m) { const c = decodeEntities(m[1].trim()).replace(/<br\s*\/?>/g, '\n'); if (c.includes('"schema_version"')) try { return JSON.parse(c); } catch(e) {} }
  return null;
};

