      error: { code: 'DEEPSEEK_BUDGET_EXCEEDED', message: `LLM budget exceeded: ${totalLlmMs}ms used of ${LLM_BUDGET_MS}ms` },
      metadata: { step: 'step_4_llm_schedule_optimization', timestamp: new Date().toISOString(), items_processed: 0, items_failed: 0, dry_run: isDryRun, llm_duration_ms: 0, llm_usage: {}, skipped: true, llm_budget_used_ms: totalLlmMs }
    }}];
  }

  // Check if DeepSeek is configured
  if (!dsConfig.api_key) {
    console.log('[SKIP] Step 4: PULSE_DEEPSEEK_API_KEY not configured');
    return [{ json: {
      success: true,
      data: { ...prevData, step_4_skipped: true, step_4_reason: 'DEEPSEEK_NOT_CONFIGURED', step_4_optimized: 0 },
      error: null,
      metadata: { step: 'step_4_llm_schedule_optimization', timestamp: new Date().toISOString(), items_processed: 0, items_failed: 0, dry_run: isDryRun, llm_duration_ms: 0, llm_usage: {}, skipped: true }
    }}];
  }

  // Fetch all today's quests from Plane.so (includes Step 2 + Step 3 created quests)
  let todayQuests = [];
  try {
    const res = await apiGet(`/projects/${config.daily_quest_project_id}/issues/?per_page=100&expand=labels,state&target_date=${todayStr}&state=${config.states.todo}`);
    todayQuests = res.results || res || [];
  } catch (e) {
    console.log(`[ERROR] Step 4: Failed to fetch today's quests: ${e.message}`);
    return [{ json: {
      success: true,
      data: { ...prevData, step_4_skipped: true, step_4_reason: 'PLANE_API_ERROR', step_4_optimized: 0 },
      error: { code: 'PLANE_API_ERROR', message: e.message },
      metadata: { step: 'step_4_llm_schedule_optimization', timestamp: new Date().toISOString(), items_processed: 0, items_failed: 0, dry_run: isDryRun, llm_duration_ms: 0, llm_usage: {}, skipped: true }
    }}];
  }

  if (todayQuests.length === 0) {
    console.log('[SKIP] Step 4: No quests to optimize');
    return [{ json: {
      success: true,
      data: { ...prevData, step_4_skipped: true, step_4_reason: 'NO_QUESTS', step_4_optimized: 0 },
      error: null,
      metadata: { step: 'step_4_llm_schedule_optimization', timestamp: new Date().toISOString(), items_processed: 0, items_failed: 0, dry_run: isDryRun, llm_duration_ms: 0, llm_usage: {}, skipped: true }
    }}];
  }

  // Build user prompt with quest details
  const questList = todayQuests.map(q => {
    const meta = extractMeta(q.description_html);
    return {
      issue_id: q.id,
      name: q.name,
      routine_time: meta?.routine_time || '--:--',
      duration_min: meta?.routine_duration_min || 30,
      priority: meta?.routine_priority || 'medium',
      mandatory: meta?.routine_mandatory || false,
    };
  });

  const userPrompt = `Today: ${todayStr}\n\nQuests to optimize (${questList.length} total):\n${JSON.stringify(questList, null, 2)}`;

  // Call DeepSeek with P-3 pattern
  let result;
  try {
    result = await withBackoff(() => callDeepSeek(SYSTEM_PROMPT, userPrompt, 0.7), 'Step 4');
  } catch (e) {
    const code = e.name === 'AbortError' || e.message?.includes('timeout') ? 'DEEPSEEK_TIMEOUT' : 'DEEPSEEK_API_ERROR';
    console.log(`[ERROR] Step 4 DeepSeek call failed: ${e.message}`);
    return [{ json: {
      success: true,
      data: { ...prevData, step_4_skipped: true, step_4_reason: code, step_4_optimized: 0 },
      error: { code, message: e.message },
      metadata: { step: 'step_4_llm_schedule_optimization', timestamp: new Date().toISOString(), items_processed: 0, items_failed: 0, dry_run: isDryRun, llm_duration_ms: Date.now() - startTime, llm_usage: {}, skipped: true }
    }}];
  }

  llmUsage = result.usage;

  // Parse and validate
  let parsed;
  try {
    parsed = JSON.parse(result.content);
    const err = validateResponse(parsed, todayQuests.length);
    if (err) throw new Error(err);
  } catch (parseErr) {
    console.log(`[WARN] Step 4 JSON validation failed: ${parseErr.message}. Retrying with temperature: 0.1`);
    try {
      result = await callDeepSeek(SYSTEM_PROMPT, userPrompt, 0.1);
      llmUsage = result.usage;
      parsed = JSON.parse(result.content);
      const err = validateResponse(parsed, todayQuests.length);
      if (err) throw new Error(err);
    } catch (retryErr) {
      console.log(`[ERROR] Step 4 second validation failed: ${retryErr.message}`);
      return [{ json: {
        success: true,
        data: { ...prevData, step_4_skipped: true, step_4_reason: 'DEEPSEEK_JSON_PARSE_ERROR', step_4_optimized: 0 },
        error: { code: 'DEEPSEEK_JSON_PARSE_ERROR', message: retryErr.message },
        metadata: { step: 'step_4_llm_schedule_optimization', timestamp: new Date().toISOString(), items_processed: 0, items_failed: 0, dry_run: isDryRun, llm_duration_ms: Date.now() - startTime, llm_usage: llmUsage, skipped: true }
      }}];
    }
  }

  llmDurationMs = Date.now() - startTime;
  totalLlmMs += llmDurationMs;
  const optimized = parsed.optimized_quests || [];
  console.log(`[INFO] Step 4: DeepSeek returned ${optimized.length} optimized quest(s) in ${llmDurationMs}ms | tokens: prompt=${llmUsage.prompt_tokens || 0}, completion=${llmUsage.completion_tokens || 0}, total=${llmUsage.total_tokens || 0}`);

  // Apply optimizations to Plane.so issues
  const questMap = new Map(todayQuests.map(q => [q.id, q]));

  for (const opt of optimized) {
    const quest = questMap.get(opt.issue_id);
    if (!quest) {
      console.log(`[WARN] Step 4: issue_id ${opt.issue_id} not found in today's quests`);
      continue;
    }

    // Update pulse-meta in description with new time and priority
    const meta = extractMeta(quest.description_html);
    if (!meta) continue;

    meta.routine_time = opt.routine_time;
    meta.routine_priority = opt.priority;
    const newMetaBlock = `<pre><code class="language-pulse-meta">${JSON.stringify(meta, null, 2)}</code></pre>`;
    // Preserve existing description content outside pulse-meta block
    let updatedDescription = quest.description_html || '';
    const metaPatterns = [
      /```pulse-meta\n[\s\S]*?\n```/,
      /<pre><code\s+class="language-pulse-meta">[\s\S]*?<\/code><\/pre>/,
      /<pre><code>[\s\S]*?"schema_version"[\s\S]*?<\/code><\/pre>/,
    ];
    let replaced = false;
    for (const pat of metaPatterns) {
      if (pat.test(updatedDescription)) {
        updatedDescription = updatedDescription.replace(pat, newMetaBlock);
        replaced = true;
        break;
      }
    }
    if (!replaced) updatedDescription = newMetaBlock + updatedDescription;

    if (isDryRun) {
      console.log(`[DRY_RUN] Would optimize "${quest.name}": time=${opt.routine_time}, priority=${opt.priority}`);
      optimizedCount++;
    } else {
      try {
        await apiPatch(`/projects/${config.daily_quest_project_id}/issues/${quest.id}/`, {
          description_html: updatedDescription,
          priority: priorityMap[opt.priority] ?? quest.priority,
        });
        optimizedCount++;
      } catch (e) {
        console.log(`[ERROR] Failed to update quest "${quest.name}": ${e.message}`);
      }
    }
  }

  return [{ json: {
    success: true,
    data: {
      ...prevData,
      step_4_skipped: false,
      step_4_optimized: optimizedCount,
    },
    error: null,
    metadata: {
      step: 'step_4_llm_schedule_optimization',
      timestamp: new Date().toISOString(),
      items_processed: optimizedCount,
      items_failed: optimized.length - optimizedCount,
      dry_run: isDryRun,
      llm_duration_ms: llmDurationMs,
      llm_usage: llmUsage,
      skipped: false,
      llm_budget_used_ms: totalLlmMs,
    }
  }}];
} catch (e) {
  console.log(`[ERROR] Step 4 unexpected error: ${e.message}`);
  return [{ json: {
    success: true,
    data: { ...prevData, step_4_skipped: true, step_4_reason: 'UNEXPECTED_ERROR', step_4_optimized: 0 },
    error: { code: 'DEEPSEEK_API_ERROR', message: e.message },
    metadata: { step: 'step_4_llm_schedule_optimization', timestamp: new Date().toISOString(), items_processed: 0, items_failed: 0, dry_run: isDryRun, llm_duration_ms: Date.now() - startTime, llm_usage: llmUsage, skipped: true }
  }}];
}

