  states: {
    todo: $env.PULSE_STATE_TODO_ID,
    deferred: $env.PULSE_STATE_DEFERRED_ID,
  },
};

const dsConfig = {
  api_key: $env.PULSE_DEEPSEEK_API_KEY,
  base_url: $env.PULSE_DEEPSEEK_BASE_URL || 'https://api.deepseek.com/v1',
  model: $env.PULSE_DEEPSEEK_MODEL || 'deepseek-chat',
};

const basePath = `${config.base_url}/api/v1/workspaces/${config.workspace_slug}`;
const headers = { 'X-API-Key': config.api_key, 'Content-Type': 'application/json' };
const isDryRun = ($env.PULSE_DRY_RUN || 'false').toLowerCase() === 'true' || ($env.PULSE_DRY_RUN || '0') === '1';
const tz = $env.PULSE_USER_TIMEZONE || 'Asia/Seoul';

// --- LLM budget tracking ---
const prevLlmMs = prevResult.metadata?.llm_budget_used_ms ?? prevResult.metadata?.llm_duration_ms ?? 0;
const LLM_BUDGET_MS = 180000;
let totalLlmMs = prevLlmMs;

// --- Retry helpers ---
const sleep = (ms) => new Promise((r) => setTimeout(r, ms));
const BACKOFF = [1000, 2000, 4000];

const withBackoff = async (fn, ctx) => {
  for (let i = 0; i < 3; i++) {
    try { return await fn(); } catch (e) {
      console.log(`[RETRY] DeepSeek ${ctx} attempt ${i + 1}/3: ${e.message}`);
      if (i === 2) throw e;
      await sleep(BACKOFF[i]);
    }
  }
};

const PER_STEP_TIMEOUT = 60000;

const callDeepSeek = async (systemPrompt, userPrompt, temperature = 0.7) => {
  const r = await _fetch(`${dsConfig.base_url}/chat/completions`, { method: 'POST', headers: { 'Authorization': `Bearer ${dsConfig.api_key}`, 'Content-Type': 'application/json' }, timeout: PER_STEP_TIMEOUT }, {
    model: dsConfig.model,
    messages: [{ role: 'system', content: systemPrompt }, { role: 'user', content: userPrompt }],
    temperature,
    max_tokens: 2048,
    response_format: { type: 'json_object' },
  });
  return { content: r.choices?.[0]?.message?.content, usage: r.usage || {} };
};

// --- Plane.so helpers ---
const apiGet = async (path) => {
  return await _fetch(`${basePath}${path}`, { headers });
};
const apiPatch = async (path, body) => {
  return await _fetch(`${basePath}${path}`, { method: 'PATCH', headers }, body);
};
const apiPost = async (path, body) => {
  return await _fetch(`${basePath}${path}`, { method: 'POST', headers }, body);
};

// --- pulse-meta parser (inline) ---
const decodeEntities = (s) => s.replace(/&quot;/g, '"').replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&#39;/g, "'");
const extractMeta = (html) => {
  if (!html) return null;
  // Pattern 1: raw markdown ```pulse-meta\n{...}\n```
  let m = html.match(/```pulse-meta\n([\s\S]*?)\n```/);
  if (m) try { return JSON.parse(m[1].trim()); } catch(e) { /* fall through */ }
  // Pattern 2: HTML with class="language-pulse-meta"
  m = html.match(/<pre><code\s+class="language-pulse-meta">([\s\S]*?)<\/code><\/pre>/);
  if (m) try { return JSON.parse(decodeEntities(m[1].trim())); } catch(e) { return null; }
  // Pattern 3: HTML with any class (e.g. language-json)
  m = html.match(/<pre><code\s[^>]*>([\s\S]*?)<\/code><\/pre>/);
  if (m) { const c = decodeEntities(m[1].trim()); if (c.includes('"schema_version"')) try { return JSON.parse(c); } catch(e) {} }
  // Pattern 4: HTML no class
  m = html.match(/<pre><code>([\s\S]*?)<\/code><\/pre>/);
  if (m) { const c = decodeEntities(m[1].trim()); if (c.includes('"schema_version"')) try { return JSON.parse(c); } catch(e) {} }
  // Pattern: inline <code> (Plane editor format, <br> line breaks)
  m = html.match(/<code[^>]*>([\s\S]*?)<\/code>/);
  if (m) { const c = decodeEntities(m[1].trim()).replace(/<br\s*\/?>/g, '\n'); if (c.includes('"schema_version"')) try { return JSON.parse(c); } catch(e) {} }
  return null;
};

// --- Prompt template ---
// Prompt source: prompts/w1-deferred-restoration.md
const SYSTEM_PROMPT = `You are a task triage assistant that evaluates deferred quests and decides which ones should be restored to today's schedule based on priority, available capacity, and deferral history.

Given the user's deferred quest list and today's current quest load, evaluate each deferred quest for restoration. Consider:
1. Priority: Higher priority deferred quests should be restored first.
2. Defer count: Quests deferred many times may indicate low relevance, or urgency if mandatory.
3. Available time: Only restore quests if there is sufficient available time in today's schedule.
4. Mandatory flag: Mandatory quests should be prioritized for restoration.

Constraints:
- Only recommend restoration for quests that fit within available capacity.
- Each entry must include: issue_id (string), name (string), restore (boolean), rationale (string, 1-2 sentences).
- Do NOT restore quests that would overload the user's day.
- Consider the total duration of today's existing quests vs available hours.
- All output must be in English.

You MUST respond with valid JSON: { "restorations": [...] }
Each entry: { "issue_id": "...", "name": "...", "restore": true/false, "rationale": "..." }`;

// --- Validation ---
const validateResponse = (parsed) => {
  if (!parsed || !Array.isArray(parsed.restorations)) return 'Missing restorations array';
  for (const r of parsed.restorations) {
    if (!r.issue_id || typeof r.issue_id !== 'string') return 'Invalid issue_id';
    if (typeof r.restore !== 'boolean') return `Invalid restore value for ${r.issue_id}`;
  }
  return null;
};

