  const restorations = parsed.restorations || [];
  const toRestore = restorations.filter(r => r.restore === true);
  console.log(`[INFO] Step 5: DeepSeek evaluated ${restorations.length} deferred quest(s), recommends restoring ${toRestore.length} in ${llmDurationMs}ms | tokens: prompt=${llmUsage.prompt_tokens || 0}, completion=${llmUsage.completion_tokens || 0}, total=${llmUsage.total_tokens || 0}`);

  // Apply restorations to Plane.so
  const deferredMap = new Map(deferredQuests.map(q => [q.id, q]));

  for (const restoration of toRestore) {
