    data: {
      ...prevData,
      step_5_skipped: false,
      step_5_restored: restoredCount,
      step_5_restorations: restoredQuests,
    },
    error: null,
    metadata: {
      step: 'step_5_llm_deferred_restoration',
      timestamp: new Date().toISOString(),
      items_processed: restoredCount,
      items_failed: toRestore.length - restoredCount,
      dry_run: isDryRun,
      llm_duration_ms: llmDurationMs,
      llm_usage: llmUsage,
      skipped: false,
      llm_budget_used_ms: totalLlmMs,
    }
  }}];
} catch (e) {
  console.log(`[ERROR] Step 5 unexpected error: ${e.message}`);
  return [{ json: {
    success: true,
    data: { ...prevData, step_5_skipped: true, step_5_reason: 'UNEXPECTED_ERROR', step_5_restored: 0, step_5_restorations: [] },
    error: { code: 'DEEPSEEK_API_ERROR', message: e.message },
    metadata: { step: 'step_5_llm_deferred_restoration', timestamp: new Date().toISOString(), items_processed: 0, items_failed: 0, dry_run: isDryRun, llm_duration_ms: Date.now() - startTime, llm_usage: llmUsage, skipped: true }
  }}];
}
